import os
from getpass import getuser

def list_user_files():
    user = getuser()
    home_dir = os.path.join('/home', user)
    files = [f for f in os.listdir(home_dir) if os.path.isfile(os.path.join(home_dir, f))]
    return files

def find_large_files(min_size):
    files = list_user_files()
    large_files = []
    for f in files:
        filepath = os.path.join('/home', getuser(), f)
        size = os.path.getsize(filepath)
        if size > min_size:
            large_files.append((filepath, size))
    return large_files

def remove_large_files(files):
    for f, size in files:
        try:
            os.chmod(f, 0o600)
            os.remove(f)
        except OSError:
            pass

if __name__ == '__main__':
    large_files = find_large_files(100000000)
    remove_large_files(large_files)

